// Lookup data generated from the official SMAA reference texture generators.
// SMAA is Copyright (C) 2013 Jorge Jimenez and contributors, distributed under the MIT license.

const areaBase64 = '';
const searchBase64 = '';

function decodeLookupData(source, size) {
    const encoded = atob(source);
    const input = new Uint8Array(encoded.length);
    for (let i = 0; i < encoded.length; i++) {
        input[i] = encoded.charCodeAt(i);
    }

    const output = new Uint8Array(size);
    let sourceOffset = 0;
    let targetOffset = 0;

    const readLength = (base) => {
        let length = base;
        if (base === 15) {
            let value;
            do {
                value = input[sourceOffset++];
                length += value;
            } while (value === 255);
        }
        return length;
    };

    while (sourceOffset < input.length) {
        const token = input[sourceOffset++];
        const literalLength = readLength(token >> 4);
        output.set(input.subarray(sourceOffset, sourceOffset + literalLength), targetOffset);
        sourceOffset += literalLength;
        targetOffset += literalLength;

        if (sourceOffset >= input.length) break;

        const matchOffset = input[sourceOffset++] | (input[sourceOffset++] << 8);
        const matchLength = readLength(token & 15) + 4;
        let matchSource = targetOffset - matchOffset;
        const matchEnd = targetOffset + matchLength;
        while (targetOffset < matchEnd) {
            output[targetOffset++] = output[matchSource++];
        }
    }

    return output;
}

function getSmaaAreaData() {
    return decodeLookupData(areaBase64, 160 * 560 * 2);
}

function getSmaaSearchData() {
    return decodeLookupData(searchBase64, 64 * 16);
}

export { getSmaaAreaData, getSmaaSearchData };
